const Q_GOVERNMENT_2008=[{"id": "objective>Government>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A member of the Commonwealth that was not colonized by Britain is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Malaysia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uganda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jamaica</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique is a member of the Commonwealth of Nations, but it was not colonized by Britain. Instead, it was colonized by Portugal. The Commonwealth of Nations is a political association of 54 member states, nearly all of which are former territories of the British Empire.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : COMMONWEALTH"}, {"id": "objective>Government>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Organization of Petroleum Exporting countries came into existence at a conference held in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tripoli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caracas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Riyadh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Baghdad</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Organization of Petroleum Exporting Countries (OPEC) was created at the Baghdad Conference on September 10–14, 1960, by Iran, Iraq, Kuwait, Saudi Arabia and Venezuela. The five founding members were later joined by other members. OPEC's objective is to co-ordinate and unify petroleum policies among Member Countries, in order to secure fair and stable prices for petroleum producers.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OPEC"}, {"id": "objective>Government>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS main achievement in recent years has been in the area of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">infrastructural development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultural integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">security and defence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political-unity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The political crises in Guinea and Mali occurred in 2021. In Guinea, a coup took place in September 2021, while Mali experienced a coup in May 2021, following an earlier one in August 2020. Both events prompted significant involvement from ECOWAS in mediation and restoration of constitutional order.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following countries has the UN carried out peacekeeping operations?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cyprus, Singapore and South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lebanon, the Congo and Mexico</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cyprus, Somalia and Yugoslavia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, Botswana and the Congo</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The United Nations (UN) has carried out peacekeeping operations in several countries around the world. Among these are Cyprus, Somalia, and Yugoslavia. The UN's peacekeeping mission in Cyprus, known as UNFICYP, was established in 1964 to prevent further fighting between the Greek Cypriot and Turkish Cypriot communities. In Somalia, the UN's mission, known as UNOSOM, was established in the early 1990s to address the civil war and humanitarian crisis. In Yugoslavia, the UN established UNPROFOR in the early 1990s to address the Yugoslav Wars. The UN has not carried out peacekeeping operations in Singapore, South Africa, Mexico, Nigeria, or Botswana.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was the main organ of the defunct OAU??</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Liberation Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Council Ministers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Commission for Mediation, Conciliation and Arbitration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Assembly of Heads of State and Government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main organ of the defunct Organization of African Unity (OAU) was the Assembly of Heads of State and Government. This assembly was the supreme organ of the OAU and it was composed of heads of state and government from all member states. It was responsible for determining the OAU's policies, goals, and objectives.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A key characteristic feature of the civil service is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transparency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">patriotism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">merit system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quota system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A key characteristic feature of the civil service is the merit system. The merit system is a system of employment where selection and promotion are based on individual ability or achievement. It is designed to ensure fairness and eliminate patronage, nepotism, and bias in the hiring and promotion process. It is a fundamental principle of public sector employment and is contrasted with the quota system, which is often seen as a form of affirmative action.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a perverted form of democracy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Feudalism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Republican </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oligarchy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perverted form of democracy is Oligarchy. In an oligarchy, power effectively rests with a small number of people. These people might be distinguished by royalty, wealth, family ties, education, corporate, religious, or military control. Such states are often controlled by families who pass their influence from one generation to the next, but inheritance is not a necessary condition for the application of this term.</div>", "topic": "FORMS OF GOVERNMENT : FEUDALISM (FEATURES, MERITS AND DEMERITS)"}, {"id": "objective>Government>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a state with an unwritten constitution is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Canada</div>", "<div style=\"font-family:Cambria;font-size:17px;\">India</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Britain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">France</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Britain is an example of a state with an unwritten constitution. An unwritten constitution is a type of constitution where the fundamental rules often take the form of customs, usage, precedent and a variety of statutes and legal instruments. An understanding of the constitution is obtained through reading commentary by the judiciary, government committees, and legal experts.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of a fascist state is the existence of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multi-party system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of a fascist state is the existence of a one-party system. Fascism is a form of far-right, authoritarian political ideology that centralizes power around a single party or leader. It suppresses opposition and criticism, and often uses a policy of belligerent nationalism and racism.</div>", "topic": "POLITICAL IDEOLOGIES : FASCISM"}, {"id": "objective>Government>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The right that enables citizens to express their electoral preferences is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">franchise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suffrage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-tails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">referendum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The right that enables citizens to express their electoral preferences is suffrage. Suffrage, also known as the right to vote, is the legal right to participate in a nation's democratic process. It is a fundamental aspect of representative democracies that allows citizens to choose their representatives in government.</div>", "topic": "THE ELECTORAL PROCESS : SUFFRAGE"}, {"id": "objective>Government>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Membership of a society is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reserved</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voluntary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mandatory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">honorary</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Membership of a society is voluntary. This means that individuals choose to join or leave a society based on their own free will. It is not reserved for certain individuals, mandatory for everyone, or honorary.</div>", "topic": "CITIZENSHIP : MEANING AND TYPES"}, {"id": "objective>Government>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Equally before the law\" is a component of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">separation of powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">checks and balances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rule of law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constitutional law</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Equally before the law\" is a component of the rule of law. The rule of law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. It means that no one is above the law, and everyone is equal before it. This principle is not directly related to separation of powers, checks and balances, or constitutional law, although these concepts can support the rule of law.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of promotional pressure group is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Supreme Council for Islamic Affairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Medical Association </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Civil Liberties Organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers Association of Nigeria</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A promotional pressure group is a type of pressure group that seeks to promote a particular cause, and they are often non-profit organizations. The Manufacturers Association of Nigeria is an example of a promotional pressure group as it seeks to promote the interests of manufacturers in Nigeria.</div>", "topic": "PRESSURE GROUPS"}, {"id": "objective>Government>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a country that operates a bicameral legislature is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sierra Leone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenya </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Libya</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bicameral legislature is a legislative body that is divided into two separate assemblies, chambers, or houses, known as a 'bicameral system'. Nigeria operates a bicameral legislature, which consists of the House of Representatives (the lower house) and the Senate (the upper house).</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An institution that transforms a myriad of demands into a more manageable proposal is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">executive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political party</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A political party is an institution that transforms a myriad of demands into a more manageable proposal. This is because political parties aggregate interests and demands from various groups and individuals, and then formulate these into policy proposals that can be implemented if the party gains power.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government exercises political power on behalf of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">party caucus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vocal few</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government exercises political power on behalf of the citizens. This is because the government is elected by the citizens and is responsible for making and implementing laws and policies that are in the best interest of the citizens. The government is accountable to the citizens and is expected to act in their best interest.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristic of a confederal state is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is supremacy of the constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the citizens often owe allegiance to the centre</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political stability is usually low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the centre overrides the regions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A confederal state is a union of states where the central authority is created by the member states and is dependent on them for its authority. The supremacy of the constitution is a major characteristic of a confederal state because the constitution is the document that outlines the powers and limitations of the central authority and the member states. The constitution is supreme because it is the highest law of the land and all other laws and actions are subject to it.</div>", "topic": "STRUCTURES OF GOVERNANCE : CONFEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The citizenship of a country can be acquired by an alien through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">habitation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">assimilation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">association</div>", "<div style=\"font-family:Cambria;font-size:17px;\">naturalization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An alien can acquire the citizenship of a country through naturalization. Naturalization is a legal process where a non-citizen in a country may acquire citizenship or nationality of that country. It may include the fulfillment of certain conditions such as residing in that country for a specified period, demonstrating good moral character, understanding of the country's language and culture, and taking an oath of allegiance.</div>", "topic": "CITIZENSHIP : MEANING AND TYPES"}, {"id": "objective>Government>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of delegated legislation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supremacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convenience</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effectiveness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficiency</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Delegated legislation refers to laws made by an individual or body under powers given to them by an Act of Parliament. The advantage of delegated legislation is its convenience. It allows the government to make changes to a law without needing to push through a completely new Act of Parliament. The whole legislative process can be time-consuming and would be even more so if every minor change in law required a completely new Act of Parliament.</div>", "topic": "PROCESSES OF LEGISLATION : DELEGATED LEGISLATION"}, {"id": "objective>Government>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A system of government that promotes the rights and freedom of the citizens is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oligarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plutocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">autocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">democracy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A system of government that promotes the rights and freedom of the citizens is called democracy. Democracy is a system of government where the citizens exercise power by voting. In a direct democracy, the citizens as a whole form a governing body and vote directly on each issue. In a representative democracy the citizens elect representatives from among themselves.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the presidential system of government, the leader is basically the head of the state and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the police</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the military</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the judiciary</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a presidential system of government, the leader is both the head of state and head of government. This means the leader is responsible for implementing and enforcing laws written by the legislature. Therefore, the correct answer is 'government'.</div>", "topic": "FORMS OF GOVERNMENT : PRESIDENTIAL SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economic system that encourages even distribution of wealth in the society is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liberalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mercantilism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Socialism is an economic system where wealth and power are shared equally among the citizens. This system encourages even distribution of wealth in the society. Therefore, the correct answer is 'socialism'.</div>", "topic": "POLITICAL IDEOLOGIES : SOCIALISM"}, {"id": "objective>Government>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An attribute that makes a state to be recognized as independent is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sovereignty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">territory</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sovereignty is the attribute that makes a state to be recognized as independent. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. It is a basic principle underlying the dominant Westphalian model of state foundation.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The act of denying an eligible person the right to vote in an election is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gerrymandering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disenfranchisement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filibustering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restricted franchise</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The act of denying an eligible person the right to vote in an election is disenfranchisement. Disenfranchisement is the revocation of the right of suffrage (the right to vote) of a person or group of people, or through practices, prevention of a person exercising the right to vote. Disenfranchisement is also termed to the revocation of power or control of a particular individual, community or being to the natural amenity they are abound in; that is to deprive of a franchise, of a legal right, of some privilege or immunity.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the monarchical system of government of government, sovereignty is vested in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">royalty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">military</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a monarchical system of government, sovereignty is vested in the royalty. This means that the monarch (king, queen, emperor, etc.) has the supreme power and authority in the state. The people, legislature, and military do not hold sovereignty in a monarchy.</div>", "topic": "SYSTEMS OF GOVERNANCE : MONARCHICAL SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One merit of a written constitution is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total flexibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rigidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ease of reference</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One merit of a written constitution is its ease of reference. A written constitution is a formal document defining the nature of the constitutional settlement, the rules that govern the political system and the rights of citizens and governments in a codified form. This makes it easy to refer to when needed. It is not totally flexible as it requires a special process to amend it, and its rigidity can be a disadvantage as it may not easily adapt to changing circumstances.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A human community that is usually cohesive and homogenous is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">state </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kinship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clan</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A nation is a human community that is usually cohesive and homogenous. This is because a nation is a large body of people united by common descent, history, culture, or language, inhabiting a particular country or territory. This makes them cohesive and homogenous. The other options do not fit the definition as accurately. A state is a political entity, a kinship is a family relationship, and a clan is a group of close-knit and interrelated families.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of implementing laws, the executive sometimes performs</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">judicial function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bureaucratic function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oversight function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislative function</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of implementing laws, the executive sometimes performs legislative functions. This is because the executive branch is responsible for the administration of the state bureaucracy, which can involve creating regulations or procedures, which is a form of legislation. Judicial function refers to the interpretation of laws, bureaucratic function refers to the administration of public policy, and oversight function refers to the review, monitoring, and supervision of government and public agencies.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following justifies the Afro-centric foreign policy of Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">her location in the West African Sub-region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Her colonization by a foreign power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Her physical size, population and resource endowments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Her ability to contribute to peace keeping missions</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Afro-centric foreign policy of Nigeria is justified by her physical size, population and resource endowments. This is because these factors give Nigeria a significant influence and role in Africa. The Afro-centric foreign policy is a policy that prioritizes the interests of Africa and its people. Nigeria, being the most populous country in Africa and rich in resources, has the capacity to influence decisions and policies in the continent.</div>", "topic": "NIGERIA'S FOREIGN POLICY"}, {"id": "objective>Government>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A virile foreign policy is one characterized by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a vibrant press, vibrant public opinion and a dynamic civil society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propaganda, espionage and economic embargoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a stable polity, buoyant economy and visionary leadership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the nature and dynamics of the international system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A virile foreign policy is characterized by a stable polity, buoyant economy and visionary leadership. A stable polity ensures that the country's foreign policy is consistent and not easily swayed by internal conflicts or instability. A buoyant economy provides the resources needed to implement the foreign policy. Visionary leadership ensures that the foreign policy is well directed and serves the best interests of the country.</div>", "topic": "NIGERIA'S FOREIGN POLICY"}, {"id": "objective>Government>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria hosted the Commonwealth conference which eventually led to the independence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mozambique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malawi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zimbabwe</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria hosted the Commonwealth conference in 1979 which eventually led to the independence of Zimbabwe. The conference was a significant event in the history of Zimbabwe as it marked the end of white minority rule and the establishment of an independent Zimbabwe.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : COMMONWEALTH"}, {"id": "objective>Government>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Multi-laterism in Nigeria's foreign policy entails her </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stand on Africa as the centrepiece of her policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-aligned posture in the international system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quest for a permanent seat in the UN Security Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">membership of international organization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Multi-lateralism in Nigeria's foreign policy entails her membership of international organizations. This is because multilateralism refers to the process of organizing relations between groups of three or more states. Beyond that, it is a method of coordinating relations between nations on the basis of 'generalized principles of conduct'. This is often in the form of membership in international organizations like the United Nations, African Union, etc.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first military coup in Nigeria toppled the government of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">General Yakubu Gowon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dr. Nnamdi Azikiwe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Abubakar Tafawa Balewa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major General Aguiyi-Ironsi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first military coup in Nigeria took place on January 15, 1966, and it was led by Major Chukwuma Kaduna Nzeogwu and Emmanuel Ifeajuna. This coup ended the First Republic and marked the beginning of a series of military regimes in Nigeria. The government that was toppled was that of Alhaji Abubakar Tafawa Balewa.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS"}, {"id": "objective>Government>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adjudication of conflict between the federal and regional governments in the First Republic was reserved for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Industrial Court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supreme Court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Court of Appeal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal High Court</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Supreme Court is the highest court in the land and it has the jurisdiction to adjudicate on matters between the federal and regional governments. Therefore, during the First Republic, conflicts between the federal and regional governments were reserved for the Supreme Court.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The officer in charge of the administration of the palace in the Yoruba political structure is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ba'ale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oluwo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ilari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iwarefa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Yoruba political structure, the officer in charge of the administration of the palace is the Oluwo. The Oluwo is a high-ranking official in the Yoruba kingdom who is responsible for the administration and maintenance of the palace. The Ba'ale is a village head, the Ilari are the king's messengers, and the Iwarefa are the senior members of the Ogboni society.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prior to 1966, the system of local government in western region was based on the three-tier structure of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">native authority, division and district councils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">district, local and area councils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">division, district and local councils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">province, district and local councils</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prior to 1966, the system of local government in the western region of Nigeria was based on the three-tier structure of native authority, division, and district councils. This system was introduced by the British colonial administration to facilitate local governance. The native authority was the highest level of local government, followed by the division and district councils.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major shortcoming of the Lyttleton Constitution was that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it did not provide for a second chamber at the federal level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Governor-General continued to head the government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no provision was made for the office of the prime minister</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it failed to provide for the office of a premier</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Lyttleton Constitution of 1954 in Nigeria did not remove the Governor-General as the head of government. The Governor-General was a representative of the British Monarch, and his position as the head of government meant that Nigeria was not fully autonomous. This was a major shortcoming of the Lyttleton Constitution.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : OLIVER LYTTLETON CONSTITUTION 1954"}, {"id": "objective>Government>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The option A-4 voting system was introduced into the political process in Nigeria during the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Third Republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fourth Republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">First Republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Second Republic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Option A-4 voting system was introduced during the Third Republic in Nigeria. This system required that a candidate must first be voted for by the majority of his party members at the local level before he could proceed to the state and national levels. This was done to ensure that only popular and acceptable candidates would emerge for elections.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FOURTH REPUBLIC"}, {"id": "objective>Government>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In orientation, early nationalism in Nigeria was essentially </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revolutionary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reformist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactionary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radical</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Early nationalism in Nigeria was essentially reformist. This is because the early nationalists sought to reform the existing colonial system rather than completely overthrow it. They aimed to improve the conditions of Nigerians within the framework of colonial rule, advocating for more representation and better treatment. This is different from being revolutionary or radical, which would involve seeking a complete overhaul of the system, or reactionary, which would involve resisting change.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE AFRICAN UNION"}, {"id": "objective>Government>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following in the Sokoto Caliphate performed functions similar to that of the Bashorun in Oyo Kingdom?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Waziri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Galadima</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ma'aji</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkali</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Sokoto Caliphate, the Waziri performed functions similar to that of the Bashorun in the Oyo Kingdom. Both the Waziri and the Bashorun were high-ranking officials who advised the ruler and played significant roles in the administration of the state. The Waziri was the vizier or prime minister in the Sokoto Caliphate, while the Bashorun was the prime minister in the Oyo Kingdom.</div>", "topic": "PRE-COLONIAL POLITICS : HAUSA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Problems arising from population census in Nigeria are mainly caused by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public opinions of people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unreliable census figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political manipulation by the elite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the registration of the under-aged people</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems arising from population census in Nigeria are mainly caused by political manipulation by the elite. This is because the census figures are often inflated or deflated for political reasons such as to gain more representation in the government or to receive more allocation of resources. This manipulation leads to unreliable census figures, which can affect planning and development.</div>", "topic": "CITIZENSHIP : MEANING AND TYPES"}, {"id": "objective>Government>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following formalized colonial penetration into Africa?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Paris Treaty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Treaty of Wesphalia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Berlin Conference</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Treaty of Versailles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Berlin Conference formalized colonial penetration into Africa. The conference, which took place from 1884 to 1885, was organized by European powers to establish rules for the colonization of Africa. It led to the 'Scramble for Africa', where European powers divided Africa into territories for colonization. The Paris Treaty, Treaty of Wesphalia, and Treaty of Versailles were significant in other historical contexts, but not directly related to the formalization of colonial penetration into Africa.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The 1989 Nigerian Constitution provided for a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multi-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-party system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1989 Nigerian Constitution provided for a two-party system. A two-party system is a form of party system where two major political parties dominate the political landscape. In the context of Nigeria, the two parties were the Social Democratic Party (SDP) and the National Republican Convention (NRC).</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian federation is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">four-tier system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three-tier system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two-tier system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-tier system</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian federation is a three-tier system. A three-tier system of government is a type of federation in which the federal government, state governments, and local government councils share powers. In Nigeria, these are the Federal, State, and Local Government levels.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : TIERS OF GOVERNMENT AND THEIR RELATIONSHIP"}, {"id": "objective>Government>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The arm of government mainly responsible for the implementation of law in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">police</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The executive arm of government is mainly responsible for the implementation of laws in Nigeria. The executive includes the president, vice president, and the cabinet. They are responsible for enforcing laws and maintaining order. The judiciary interprets the laws, the legislature makes the laws, and the police enforce the laws, but the executive is the one that implements them.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The British colonial rule in Nigeria brought about </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a stagnation in social formations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pampering of traditional rulers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in the mode of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilization in the price of raw materials</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The British colonial rule in Nigeria brought about a change in the mode of production. Before the British rule, Nigerians were mainly engaged in subsistence farming and local crafts. However, the British introduced cash crop farming and mining, which changed the mode of production from subsistence to commercial. This led to a significant change in the economic structure of the society.</div>", "topic": "IMPERIALIST PENETRATION : IMPACT OF BRITISH COLONIAL RULE- ECONOMIC, POLITICAL, SOCIO-CULTURAL"}, {"id": "objective>Government>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A primary objective of the privatization policy in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">probity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">responsiveness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transparency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accountability</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of the privatization policy in Nigeria is to reduce the involvement of the state in the economy, increase efficiency and productivity, and attract foreign investment.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is saddled with the conduct of general elections in Nigeria's Fourth Republic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Electoral Commission of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Independent National Electoral Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Electoral Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Electoral Commission</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Independent National Electoral Commission (INEC) is the body saddled with the conduct of general elections in Nigeria's Fourth Republic. It was established in 1998 and is responsible for organizing elections into various political offices in the country.</div>", "topic": "THE ELECTORAL PROCESS"}, {"id": "objective>Government>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public corporations are established to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce government spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boost government revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve provision of social appointments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create vacancies for political appointments</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public corporations are established by the government to provide essential services to the public. They are not primarily focused on reducing government spending or boosting government revenue, but rather on improving the provision of social services. This can include things like transportation, utilities, and healthcare. Therefore, the correct answer is 'improve provision of social appointments'.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The political structure of Nigeria under the first military regime was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">confederal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quasi-federal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitary</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The political structure of Nigeria under the first military regime was unitary. In a unitary system, all powers are concentrated in the central government, and the states or provinces are subordinate. This was the case in Nigeria under the first military regime, where the Federal Military Government held all the powers. Therefore, the correct answer is 'unitary'.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}];
